"""Codex-local Python sandbox adjustments for PubCast.

The Codex desktop sandbox can execute the project Python, but Windows temp
folders created through tempfile.mkdtemp() can inherit permissions that block
follow-up writes by the same sandbox process. Keep Python temp work inside the
repo with normal inherited directory permissions.
"""
from __future__ import annotations

import os
import tempfile
import uuid
from pathlib import Path


ROOT = Path(r"C:\Users\hardc\OneDrive\Documents\Playground\Pubcast codex run")
TEMP_ROOT = ROOT / ".codex_python_temp"
TEMP_ROOT.mkdir(parents=True, exist_ok=True)

for key in ("TMPDIR", "TEMP", "TMP"):
    os.environ.setdefault(key, str(TEMP_ROOT))

tempfile.tempdir = str(TEMP_ROOT)
_original_mkdtemp = tempfile.mkdtemp


def _codex_mkdtemp(suffix=None, prefix=None, dir=None):
    base = Path(dir) if dir else TEMP_ROOT
    base.mkdir(parents=True, exist_ok=True)
    safe_prefix = "tmp" if prefix is None else str(prefix)
    safe_suffix = "" if suffix is None else str(suffix)
    for _ in range(100):
        candidate = base / f"{safe_prefix}{uuid.uuid4().hex}{safe_suffix}"
        try:
            candidate.mkdir()
            return str(candidate)
        except FileExistsError:
            continue
    return _original_mkdtemp(suffix=suffix, prefix=prefix, dir=str(base))


tempfile.mkdtemp = _codex_mkdtemp
